package com.cognizant.springlearn.service; import com.cognizant.springlearn.dao.CountryDao; import com.cognizant.springlearn.model.Country; import org.springframework.stereotype.Service; import java.util.List; @Service public class CountryService { private final CountryDao countryDao; public CountryService(CountryDao countryDao){this.countryDao=countryDao;} public Country addCountry(Country country){return countryDao.add(country);} public List<Country> getAllCountries(){return countryDao.getAll();} }
